import numpy as np
def predict(frame: np.ndarray, action: int) -> np.ndarray:
    result = frame.copy()
    row0 = frame[0, :]
    nonzero = row0[row0 > 0]
    mx = int(nonzero.max()) if len(nonzero) > 0 else 1
    for c in range(64):
        if frame[0, c] < mx:
            result[0, c] = frame[0, c] + 1
            return result
    # All cells at mx: advance one more (new frontier)
    for c in range(64):
        if frame[0, c] == mx:
            result[0, c] = mx + 1
            break
    return result
